#include <unordered_map>
#include <mutex>

template<typename K, typename V>
class Cache {
    struct Node {
        K key;
        V value;
        Node* prev;
        Node* next;
        Node(K k, V v) : key(k), value(v), prev(nullptr), next(nullptr) {}
    };

    std::unordered_map<K, Node*> map;
    Node* head = nullptr;
    Node* tail = nullptr;
    int capacity;
    int size = 0;
    std::mutex mtx;

    void removeNode(Node* node) {
        if (node->prev) node->prev->next = node->next;
        else head = node->next;
        if (node->next) node->next->prev = node->prev;
        else tail = node->prev;
    }

    void addToFront(Node* node) {
        node->next = head;
        node->prev = nullptr;
        if (head) head->prev = node;
        head = node;
        if (!tail) tail = head;
    }

public:
    Cache(int cap) : capacity(cap) {}

    V get(const K& key) {
        std::lock_guard<std::mutex> lock(mtx);
        if (map.find(key) == map.end()) return V();
        Node* node = map[key];
        removeNode(node);
        addToFront(node);
        return node->value;
    }

    void put(const K& key, const V& value) {
        std::lock_guard<std::mutex> lock(mtx);
        if (map.find(key) != map.end()) {
            Node* node = map[key];
            node->value = value;
            removeNode(node);
            addToFront(node);
        } else {
            Node* node = new Node(key, value);
            if (size == capacity) {
                map.erase(tail->key);
                removeNode(tail);
            } else {
                size++;
            }
            addToFront(node);
            map[key] = node;
        }
    }

    ~Cache() {
        Node* curr = head;
        while (curr) {
            Node* next = curr->next;
            delete curr;
            curr = next;
        }
    }
};

